#include "biblia.h"

void Biblia::Carregar1Joao(Biblia* b) {
    b->dados[JOAO1].nome = wxT("1 João");

    b->dados[JOAO1].capitulos[1].versos[1] = wxT("O que era desde o princípio, o que ouvimos, o que vimos com os nossos olhos, o que contemplamos e as nossas mãos apalparam, a respeito do Verbo da vida");
    b->dados[JOAO1].capitulos[1].versos[2] = wxT("{pois a vida foi manifestada, e nós a temos visto, e dela testificamos, e vos anunciamos a vida eterna, que estava com o Pai, e a nós foi manifestada};");
    b->dados[JOAO1].capitulos[1].versos[3] = wxT("sim, o que vimos e ouvimos, isso vos anunciamos, para que vós também tenhais comunhão conosco; e a nossa comunhão é com o Pai, e com seu Filho Jesus Cristo.");
    b->dados[JOAO1].capitulos[1].versos[4] = wxT("Estas coisas vos escrevemos, para que o nosso gozo seja completo.");
    b->dados[JOAO1].capitulos[1].versos[5] = wxT("E esta é a mensagem que dele ouvimos, e vos anunciamos: que Deus é luz, e nele não há trevas nenhumas.");
    b->dados[JOAO1].capitulos[1].versos[6] = wxT("Se dissermos que temos comunhão com ele, e andarmos nas trevas, mentimos, e não praticamos a verdade;");
    b->dados[JOAO1].capitulos[1].versos[7] = wxT("mas, se andarmos na luz, como ele na luz está, temos comunhão uns com os outros, e o sangue de Jesus seu Filho nos purifica de todo pecado.");
    b->dados[JOAO1].capitulos[1].versos[8] = wxT("Se dissermos que não temos pecado nenhum, enganamo-nos a nós mesmos, e a verdade não está em nós.");
    b->dados[JOAO1].capitulos[1].versos[9] = wxT("Se confessarmos os nossos pecados, ele é fiel e justo para nos perdoar os pecados e nos purificar de toda injustiça.");
    b->dados[JOAO1].capitulos[1].versos[10] = wxT("Se dissermos que não temos cometido pecado, fazemo-lo mentiroso, e a sua palavra não está em nós.");

    b->dados[JOAO1].capitulos[2].versos[1] = wxT("Meus filhinhos, estas coisas vos escrevo, para que não pequeis; mas, se alguém pecar, temos um Advogado para com o Pai, Jesus Cristo, o justo.");
    b->dados[JOAO1].capitulos[2].versos[2] = wxT("E ele é a propiciação pelos nossos pecados, e não somente pelos nossos, mas também pelos de todo o mundo.");
    b->dados[JOAO1].capitulos[2].versos[3] = wxT("E nisto sabemos que o conhecemos; se guardamos os seus mandamentos.");
    b->dados[JOAO1].capitulos[2].versos[4] = wxT("Aquele que diz: Eu o conheço, e não guarda os seus mandamentos, é mentiroso, e nele não está a verdade;");
    b->dados[JOAO1].capitulos[2].versos[5] = wxT("mas qualquer que guarda a sua palavra, nele realmente se tem aperfeiçoado o amor de Deus. E nisto sabemos que estamos nele;");
    b->dados[JOAO1].capitulos[2].versos[6] = wxT("aquele que diz estar nele, também deve andar como ele andou.");
    b->dados[JOAO1].capitulos[2].versos[7] = wxT("Amados, não vos escrevo mandamento novo, mas um mandamento antigo, que tendes desde o princípio. Este mandamento antigo é a palavra que ouvistes.");
    b->dados[JOAO1].capitulos[2].versos[8] = wxT("Contudo é um novo mandamento que vos escrevo, o qual é verdadeiro nele e em vós; porque as trevas vão passando, e já brilha a verdadeira luz.");
    b->dados[JOAO1].capitulos[2].versos[9] = wxT("Aquele que diz estar na luz, e odeia a seu irmão, até agora está nas trevas.");
    b->dados[JOAO1].capitulos[2].versos[10] = wxT("Aquele que ama a seu irmão permanece na luz, e nele não há tropeço.");
    b->dados[JOAO1].capitulos[2].versos[11] = wxT("Mas aquele que odeia a seu irmão está nas trevas, e anda nas trevas, e não sabe para onde vai; porque as trevas lhe cegaram os olhos.");
    b->dados[JOAO1].capitulos[2].versos[12] = wxT("Filhinhos, eu vos escrevo, porque os vossos pecados são perdoados por amor do seu nome.");
    b->dados[JOAO1].capitulos[2].versos[13] = wxT("Pais, eu vos escrevo, porque conheceis aquele que é desde o princípio. Jovens, eu vos escrevo, porque vencestes o Maligno.");
    b->dados[JOAO1].capitulos[2].versos[14] = wxT("Eu vos escrevi, meninos, porque conheceis o Pai. Eu vos escrevi, pais, porque conheceis aquele que é desde o princípio. Eu escrevi, jovens, porque sois fortes, e a palavra de Deus permanece em vós, e já vencestes o Maligno.");
    b->dados[JOAO1].capitulos[2].versos[15] = wxT("Não ameis o mundo, nem o que há no mundo. Se alguém ama o mundo, o amor do Pai não está nele.");
    b->dados[JOAO1].capitulos[2].versos[16] = wxT("Porque tudo o que há no mundo, a concupiscência da carne, a concupiscência dos olhos e a soberba da vida, não vem do Pai, mas sim do mundo.");
    b->dados[JOAO1].capitulos[2].versos[17] = wxT("Ora, o mundo passa, e a sua concupiscência; mas aquele que faz a vontade de Deus, permanece para sempre.");
    b->dados[JOAO1].capitulos[2].versos[18] = wxT("Filhinhos, esta é a última hora; e, conforme ouvistes que vem o anticristo, já muitos anticristos se têm levantado; por onde conhecemos que é a última hora.");
    b->dados[JOAO1].capitulos[2].versos[19] = wxT("Saíram dentre nós, mas não eram dos nossos; porque, se fossem dos nossos, teriam permanecido conosco; mas todos eles saíram para que se manifestasse que não são dos nossos.");
    b->dados[JOAO1].capitulos[2].versos[20] = wxT("Ora, vós tendes a unção da parte do Santo, e todos tendes conhecimento.");
    b->dados[JOAO1].capitulos[2].versos[21] = wxT("Não vos escrevi porque não soubésseis a verdade, mas porque a sabeis, e porque nenhuma mentira vem da verdade.");
    b->dados[JOAO1].capitulos[2].versos[22] = wxT("Quem é o mentiroso, senão aquele que nega que Jesus é o Cristo? Esse mesmo é o anticristo, esse que nega o Pai e o Filho.");
    b->dados[JOAO1].capitulos[2].versos[23] = wxT("Qualquer que nega o Filho, também não tem o Pai; aquele que confessa o Filho, tem também o Pai.");
    b->dados[JOAO1].capitulos[2].versos[24] = wxT("Portanto, o que desde o princípio ouvistes, permaneça em vós. Se em vós permanecer o que desde o princípio ouvistes, também vós permanecereis no Filho e no Pai.");
    b->dados[JOAO1].capitulos[2].versos[25] = wxT("E esta é a promessa que ele nos fez: a vida eterna.");
    b->dados[JOAO1].capitulos[2].versos[26] = wxT("Estas coisas vos escrevo a respeito daqueles que vos querem enganar.");
    b->dados[JOAO1].capitulos[2].versos[27] = wxT("E quanto a vós, a unção que dele recebestes fica em vós, e não tendes necessidade de que alguém vos ensine; mas, como a sua unção vos ensina a respeito de todas as coisas, e é verdadeira, e não é mentira, como vos ensinou ela, assim nele permanecei.");
    b->dados[JOAO1].capitulos[2].versos[28] = wxT("E agora, filhinhos, permanecei nele; para que, quando ele se manifestar, tenhamos confiança, e não fiquemos confundidos diante dele na sua vinda.");
    b->dados[JOAO1].capitulos[2].versos[29] = wxT("Se sabeis que ele é justo, sabeis que todo aquele que pratica a justiça é nascido dele.");

    b->dados[JOAO1].capitulos[3].versos[1] = wxT("Vede que grande amor nos tem concedido o Pai: que fôssemos chamados filhos de Deus; e nós o somos. Por isso o mundo não nos conhece; porque não conheceu a ele.");
    b->dados[JOAO1].capitulos[3].versos[2] = wxT("Amados, agora somos filhos de Deus, e ainda não é manifesto o que havemos de ser. Mas sabemos que, quando ele se manifestar, seremos semelhantes a ele; porque assim como é, o veremos.");
    b->dados[JOAO1].capitulos[3].versos[3] = wxT("E todo o que nele tem esta esperança, purifica-se a si mesmo, assim como ele é puro.");
    b->dados[JOAO1].capitulos[3].versos[4] = wxT("Todo aquele que vive habitualmente no pecado também vive na rebeldia, pois o pecado é rebeldia.");
    b->dados[JOAO1].capitulos[3].versos[5] = wxT("E bem sabeis que ele se manifestou para tirar os pecados; e nele não há pecado.");
    b->dados[JOAO1].capitulos[3].versos[6] = wxT("Todo o que permanece nele não vive pecando; todo o que vive pecando não o viu nem o conhece.");
    b->dados[JOAO1].capitulos[3].versos[7] = wxT("Filhinhos, ninguém vos engane; quem pratica a justiça é justo, assim como ele é justo;");
    b->dados[JOAO1].capitulos[3].versos[8] = wxT("quem comete pecado é do Diabo; porque o Diabo peca desde o princípio. Para isto o Filho de Deus se manifestou: para destruir as obras do Diabo.");
    b->dados[JOAO1].capitulos[3].versos[9] = wxT("Aquele que é nascido de Deus não peca habitualmente; porque a semente de Deus permanece nele, e não pode continuar no pecado, porque é nascido de Deus.");
    b->dados[JOAO1].capitulos[3].versos[10] = wxT("Nisto são manifestos os filhos de Deus, e os filhos do Diabo: quem não pratica a justiça não é de Deus, nem o que não ama a seu irmão.");
    b->dados[JOAO1].capitulos[3].versos[11] = wxT("Porque esta é a mensagem que ouvistes desde o princípio, que nos amemos uns aos outros,");
    b->dados[JOAO1].capitulos[3].versos[12] = wxT("não sendo como Caim, que era do Maligno, e matou a seu irmão. E por que o matou? Porque as suas obras eram más e as de seu irmão justas.");
    b->dados[JOAO1].capitulos[3].versos[13] = wxT("Meus irmãos, não vos admireis se o mundo vos odeia.");
    b->dados[JOAO1].capitulos[3].versos[14] = wxT("Nós sabemos que já passamos da morte para a vida, porque amamos os irmãos. Quem não ama permanece na morte.");
    b->dados[JOAO1].capitulos[3].versos[15] = wxT("Todo o que odeia a seu irmão é homicida; e vós sabeis que nenhum homicida tem a vida eterna permanecendo nele.");
    b->dados[JOAO1].capitulos[3].versos[16] = wxT("Nisto conhecemos o amor: que Cristo deu a sua vida por nós; e nós devemos dar a vida pelos irmãos.");
    b->dados[JOAO1].capitulos[3].versos[17] = wxT("Quem, pois, tiver bens do mundo, e, vendo o seu irmão necessitando, lhe fechar o seu coração, como permanece nele o amor de Deus?");
    b->dados[JOAO1].capitulos[3].versos[18] = wxT("Filhinhos, não amemos de palavra, nem de língua, mas por obras e em verdade.");
    b->dados[JOAO1].capitulos[3].versos[19] = wxT("Nisto conheceremos que somos da verdade, e diante dele tranqüilizaremos o nosso coração;");
    b->dados[JOAO1].capitulos[3].versos[20] = wxT("porque se o coração nos condena, maior é Deus do que o nosso coração, e conhece todas as coisas.");
    b->dados[JOAO1].capitulos[3].versos[21] = wxT("Amados, se o coração não nos condena, temos confiança para com Deus;");
    b->dados[JOAO1].capitulos[3].versos[22] = wxT("e qualquer coisa que lhe pedirmos, dele a receberemos, porque guardamos os seus mandamentos, e fazemos o que é agradável à sua vista.");
    b->dados[JOAO1].capitulos[3].versos[23] = wxT("Ora, o seu mandamento é este, que creiamos no nome de seu Filho Jesus Cristo, e nos amemos uns aos outros, como ele nos ordenou.");
    b->dados[JOAO1].capitulos[3].versos[24] = wxT("Quem guarda os seus mandamentos, em Deus permanece e Deus nele. E nisto conhecemos que ele permanece em nós: pelo Espírito que nos tem dado.");

}
